self.addEventListener("push",t=>{let i={title:"SMEL-Plataforma de Eventos",body:"Voc\xea tem uma nova notifica\xe7\xe3o!"};if(t.data)try{i=t.data.json()}catch(a){i={title:"SMEL-Plataforma de Eventos",body:t.data.text()}}let a={body:i.body,icon:"/icon-192.png",badge:"/icon-192.png",data:{url:i.url||"/"}};t.waitUntil(self.registration.showNotification(i.title,a))}),self.addEventListener("notificationclick",t=>{t.notification.close(),t.waitUntil(clients.openWindow(t.notification.data.url||"/"))});